#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { long double w, wy, wy2; } Block;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        double *A = (double*)malloc(N*sizeof(double));
        double *B = (double*)malloc(N*sizeof(double));
        for(int i=0;i<N;i++) scanf("%lf", &A[i]);
        for(int i=0;i<N;i++) scanf("%lf", &B[i]);
        Block *st = (Block*)malloc(N*sizeof(Block));
        int top = 0;
        for(int i=0;i<N;i++){
            long double wi = (long double)B[i]*B[i];
            long double yi = (long double)A[i]/B[i];
            st[top].w = wi;
            st[top].wy = wi*yi;
            st[top].wy2 = wi*yi*yi;
            top++;
            while(top>=2){
                long double avgPrev = st[top-2].wy / st[top-2].w;
                long double avgCurr = st[top-1].wy / st[top-1].w;
                if(avgPrev < avgCurr - 1e-18L){ // violation of non‑increasing
                    // merge
                    st[top-2].wy += st[top-1].wy;
                    st[top-2].w  += st[top-1].w;
                    st[top-2].wy2+= st[top-1].wy2;
                    top--;
                }else break;
            }
        }
        long double ans = 0.0L;
        for(int i=0;i<top;i++){
            long double avg = st[i].wy / st[i].w;
            ans += st[i].wy2 - 2.0L*avg*st[i].wy + avg*avg*st[i].w;
        }
        printf("%.15Lf\n", ans);
        free(A); free(B); free(st);
    }
    return 0;
}

