import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c;
            while ((c = readByte()) <= ' ') if (c == -1) return Long.MIN_VALUE;
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
    static class Block {
        long double w, wy, wy2;
        Block(long double w, long double wy, long double wy2){ this.w=w; this.wy=wy; this.wy2=wy2; }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = fs.nextInt();
            long[] A = new long[N];
            long[] B = new long[N];
            for (int i = 0; i < N; i++) A[i] = fs.nextLong();
            for (int i = 0; i < N; i++) B[i] = fs.nextLong();
            ArrayDeque<Block> stack = new ArrayDeque<>();
            for (int i = 0; i < N; i++) {
                long double wi = (long double)B[i] * B[i];
                long double yi = (long double)A[i] / B[i];
                stack.addLast(new Block(wi, wi * yi, wi * yi * yi));
                while (stack.size() >= 2) {
                    Block last = stack.removeLast();
                    Block prev = stack.peekLast();
                    long double avgPrev = prev.wy / prev.w;
                    long double avgLast = last.wy / last.w;
                    if (avgPrev < avgLast - 1e-18L) {
                        prev.w  += last.w;
                        prev.wy += last.wy;
                        prev.wy2+= last.wy2;
                    } else {
                        stack.addLast(last);
                        break;
                    }
                }
            }
            long double ans = 0.0L;
            for (Block b : stack) {
                long double avg = b.wy / b.w;
                ans += b.wy2 - 2.0L * avg * b.wy + avg * avg * b.w;
            }
            sb.append(String.format(Locale.US, "%.15f\n", (double)ans));
        }
        System.out.print(sb.toString());
    }
}

