let idx = 0;
const T = data[idx++];
let out = [];
for (let tc = 0; tc < T; tc++) {
  const N = data[idx++];
  const A = new Array(N);
  const B = new Array(N);
  for (let i = 0; i < N; i++) A[i] = data[idx++];
  for (let i = 0; i < N; i++) B[i] = data[idx++];
  const w = [];
  const wy = [];
  const wy2 = [];
  for (let i = 0; i < N; i++) {
    const wi = B[i] * B[i];
    const yi = A[i] / B[i];
    w.push(wi);
    wy.push(wi * yi);
    wy2.push(wi * yi * yi);
    while (w.length >= 2) {
      const avgPrev = wy[w.length - 2] / w[w.length - 2];
      const avgCurr = wy[w.length - 1] / w[w.length - 1];
      if (avgPrev < avgCurr - 1e-18) {
        const wNew = w[w.length - 2] + w[w.length - 1];
        const wyNew = wy[w.length - 2] + wy[w.length - 1];
        const wy2New = wy2[w.length - 2] + wy2[w.length - 1];
        w[w.length - 2] = wNew;
        wy[w.length - 2] = wyNew;
        wy2[w.length - 2] = wy2New;
        w.pop(); wy.pop(); wy2.pop();
      } else break;
    }
  }
  let ans = 0.0;
  for (let i = 0; i < w.length; i++) {
    const avg = wy[i] / w[i];
    ans += wy2[i] - 2.0 * avg * wy[i] + avg * avg * w[i];
  }
  out.push(ans.toFixed(15));
}
